import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { register } from '../api';

export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '', confirm: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { loginUser } = useAuth();
  const navigate = useNavigate();

  const handle = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const submit = async (e) => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirm) return setError('Passwords do not match');
    if (form.password.length < 6) return setError('Password must be at least 6 characters');
    setLoading(true);
    try {
      const res = await register({ name: form.name, email: form.email, password: form.password });
      loginUser({ id: res.data.user_id, name: res.data.name, email: form.email }, res.data.access_token);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.detail || 'Registration failed. Please try again.');
    } finally { setLoading(false); }
  };

  return (
    <div style={styles.page}>
      <div style={styles.left}>
        <div style={styles.leftContent}>
          <div style={styles.logo}>🌱 MindEase</div>
          <h1 style={styles.headline}>Start your wellness journey today</h1>
          <p style={styles.sub}>Join thousands of students taking their mental health seriously. Free, safe, and always there when you need it.</p>
          <div style={styles.tagline}>
            <span style={styles.tagChip}>💚 Evidence-based</span>
            <span style={styles.tagChip}>🔒 100% Private</span>
            <span style={styles.tagChip}>🎓 Made for students</span>
          </div>
        </div>
      </div>
      <div style={styles.right}>
        <div style={styles.formCard}>
          <h2 style={styles.formTitle}>Create your account</h2>
          <p style={styles.formSub}>It only takes a minute</p>
          {error && <div style={styles.errorBox}>{error}</div>}
          <form onSubmit={submit} style={styles.form}>
            <div style={styles.field}>
              <label style={styles.label}>Full Name</label>
              <input name="name" type="text" required value={form.name} onChange={handle}
                className="input-field" placeholder="Your name" />
            </div>
            <div style={styles.field}>
              <label style={styles.label}>College Email</label>
              <input name="email" type="email" required value={form.email} onChange={handle}
                className="input-field" placeholder="you@college.edu" />
            </div>
            <div style={styles.field}>
              <label style={styles.label}>Password</label>
              <input name="password" type="password" required value={form.password} onChange={handle}
                className="input-field" placeholder="At least 6 characters" />
            </div>
            <div style={styles.field}>
              <label style={styles.label}>Confirm Password</label>
              <input name="confirm" type="password" required value={form.confirm} onChange={handle}
                className="input-field" placeholder="Repeat your password" />
            </div>
            <button type="submit" className="btn-primary" style={styles.submitBtn} disabled={loading}>
              {loading ? 'Creating account…' : 'Create account →'}
            </button>
          </form>
          <p style={styles.switchLink}>
            Already have an account? <Link to="/login" style={styles.link}>Sign in</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { display: 'flex', minHeight: '100vh' },
  left: {
    flex: 1, background: 'linear-gradient(145deg, var(--teal-dark) 0%, var(--sage) 100%)',
    display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 48,
  },
  leftContent: { maxWidth: 440, color: 'white' },
  logo: { fontFamily: 'var(--font-serif)', fontSize: '1.6rem', marginBottom: 32, opacity: 0.9 },
  headline: { fontSize: '2.6rem', marginBottom: 16, lineHeight: 1.15, color: 'white' },
  sub: { fontSize: '1.05rem', opacity: 0.85, marginBottom: 36, lineHeight: 1.6 },
  tagline: { display: 'flex', gap: 10, flexWrap: 'wrap' },
  tagChip: { background: 'rgba(255,255,255,0.2)', padding: '6px 14px', borderRadius: 99, fontSize: '0.85rem' },
  right: { width: 460, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 40, background: 'var(--surface)' },
  formCard: { width: '100%', maxWidth: 380 },
  formTitle: { fontSize: '2rem', marginBottom: 6, color: 'var(--ink)' },
  formSub: { color: 'var(--mist)', marginBottom: 28 },
  errorBox: { background: 'var(--rose-pale)', border: '1px solid var(--rose)', color: '#b03a4a', padding: '10px 14px', borderRadius: 'var(--radius-sm)', marginBottom: 16, fontSize: '0.9rem' },
  form: { display: 'flex', flexDirection: 'column', gap: 16 },
  field: { display: 'flex', flexDirection: 'column', gap: 6 },
  label: { fontSize: '0.85rem', fontWeight: 600, color: 'var(--ink-light)' },
  submitBtn: { width: '100%', marginTop: 8, padding: '14px' },
  switchLink: { textAlign: 'center', marginTop: 20, fontSize: '0.9rem', color: 'var(--mist)' },
  link: { color: 'var(--teal)', fontWeight: 600 },
};
